CREATE TABLE payment_logs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), gateway text NOT NULL, mode text NOT NULL CHECK (mode IN ('test','live')), event_type text NOT NULL, status text NOT NULL CHECK (status IN ('success','failed','pending')), reference_id text, amount numeric(10,2), currency text, request_body jsonb, response_body jsonb, error_message text, ip_address text, user_agent text, processed_at timestamptz DEFAULT now(), created_at timestamptz DEFAULT now()); CREATE INDEX idx_payment_logs_gateway ON payment_logs(gateway); CREATE INDEX idx_payment_logs_created_at ON payment_logs(created_at DESC); CREATE INDEX idx_payment_logs_status ON payment_logs(status); ALTER TABLE payment_logs ENABLE ROW LEVEL SECURITY; CREATE POLICY admin_all_payment_logs ON payment_logs FOR ALL USING (EXISTS (SELECT 1 FROM profiles WHERE profiles.id = auth.uid() AND profiles.role = 'admin'));